Below is a ready-to-use solution to automatically compare the currently checked-out (local) version of your site with the live (production) version across multiple screen sizes and fail when visual differences exceed a configured threshold.

What it does
- Uses Puppeteer to load both local and live pages and take screenshots at each configured viewport (screen size).
- Optionally hides/masks dynamic selectors (timestamps, ads, user-specific content) so they don't generate false positives.
- Compares screenshots with pixelmatch and writes a diff image when differences exist.
- Exits non-zero when any comparison exceeds a configured percentage difference, making it suitable for CI gating after dependency updates.

Files to add
1) package.json (install deps)
2) visual-config.json (configurable URLs, pages, viewports, threshold, masks)
3) compare.js (main script)
4) Optional: GitHub Actions workflow example to run in CI

--- package.json ---
Save this as package.json in your repo root:
{
  "name": "visual-regression-check",
  "version": "1.0.0",
  "private": true,
  "scripts": {
    "visual:compare": "node compare.js"
  },
  "devDependencies": {
    "pixelmatch": "^5.3.0",
    "pngjs": "^6.0.0",
    "puppeteer": "^21.0.0",
    "mkdirp": "^1.0.4"
  }
}

Install dependencies:
- npm install --no-audit --no-fund
(You can adjust versions as needed. Puppeteer downloads Chromium by default. In CI you might use PLAYWRIGHT or set PUPPETEER_SKIP_CHROMIUM_DOWNLOAD depending on environment.)

--- visual-config.json ---
Save this config file in the repo root and edit for your site:
{
  "localBase": "http://localhost:3000",
  "liveBase": "https://www.example.com",
  "pages": [
    "/",
    "/about",
    "/products"
  ],
  "viewports": [
    { "name": "mobile", "width": 375, "height": 812 },
    { "name": "tablet", "width": 768, "height": 1024 },
    { "name": "desktop", "width": 1366, "height": 768 }
  ],
  "outputDir": "visual-output",
  "thresholdPercent": 0.1,
  "waitUntil": "networkidle2",
  "waitMsAfterLoad": 250,
  "hideSelectors": [
    ".timestamp",
    ".ad-slot",
    ".dynamic-counter"
  ]
}

Meaning of important options:
- localBase: URL where the currently checked-out site is served (e.g., your dev server). Ensure it's running during the test.
- liveBase: production/live base URL.
- pages: array of paths to compare.
- viewports: screen sizes to test (name, width, height).
- thresholdPercent: maximum allowed percentage of differing pixels (e.g., 0.1 is 0.1%).
- hideSelectors: CSS selectors to hide before screenshots (set to empty [] if not needed).
- outputDir: where screenshots/diffs are saved.

--- compare.js ---
Save this file in the repo root as compare.js:

const fs = require('fs');
const path = require('path');
const mkdirp = require('mkdirp');
const puppeteer = require('puppeteer');
const { PNG } = require('pngjs');
const pixelmatch = require('pixelmatch');

const CONFIG_PATH = path.resolve(process.cwd(), 'visual-config.json');

function readConfig() {
  if (!fs.existsSync(CONFIG_PATH)) {
    console.error('Config file not found:', CONFIG_PATH);
    process.exit(2);
  }
  return JSON.parse(fs.readFileSync(CONFIG_PATH, 'utf8'));
}

function screenshotFilename(outputDir, which, pagePath, vpName) {
  // sanitize pagePath to a filename
  const safePath = pagePath === '/' ? 'root' : pagePath.replace(/\//g, '_').replace(/^_+|_+$/g, '');
  return path.join(outputDir, `${safePath}__${vpName}__${which}.png`);
}

async function hideSelectors(page, selectors = []) {
  if (!selectors || selectors.length === 0) return;
  const css = selectors.map(s => `${s} { visibility: hidden !important; opacity: 0 !important; }`).join('\n');
  await page.addStyleTag({ content: css });
}

async function snapPage(page, url, filePath, waitUntil, waitMsAfterLoad) {
  await page.goto(url, { waitUntil: waitUntil || 'networkidle2', timeout: 60000 });
  if (waitMsAfterLoad && waitMsAfterLoad > 0) {
    await page.waitForTimeout(waitMsAfterLoad);
  }
  await page.screenshot({ path: filePath, fullPage: true });
}

function compareImages(imgPathA, imgPathB, outDiffPath) {
  const imgA = PNG.sync.read(fs.readFileSync(imgPathA));
  const imgB = PNG.sync.read(fs.readFileSync(imgPathB));

  if (imgA.width !== imgB.width || imgA.height !== imgB.height) {
    // If sizes differ, create a blank diff and return 100% diff
    const maxW = Math.max(imgA.width, imgB.width);
    const maxH = Math.max(imgA.height, imgB.height);
    const diff = new PNG({ width: maxW, height: maxH });
    fs.writeFileSync(outDiffPath, PNG.sync.write(diff));
    return { diffPixels: maxW * maxH, totalPixels: maxW * maxH };
  }

  const { width, height } = imgA;
  const diff = new PNG({ width, height });
  const diffPixels = pixelmatch(imgA.data, imgB.data, diff.data, width, height, { threshold: 0.1 });
  fs.writeFileSync(outDiffPath, PNG.sync.write(diff));
  return { diffPixels, totalPixels: width * height };
}

(async () => {
  const cfg = readConfig();
  const outDir = path.resolve(process.cwd(), cfg.outputDir || 'visual-output');
  mkdirp.sync(outDir);

  const browser = await puppeteer.launch({
    args: ['--no-sandbox', '--disable-setuid-sandbox']
  });

  const page = await browser.newPage();

  let failures = 0;
  const results = [];

  for (const pagePath of cfg.pages) {
    for (const vp of cfg.viewports) {
      const vpName = vp.name || `${vp.width}x${vp.height}`;
      await page.setViewport({ width: vp.width, height: vp.height });

      const localUrl = new URL(pagePath, cfg.localBase).href;
      const liveUrl = new URL(pagePath, cfg.liveBase).href;

      const localShot = screenshotFilename(outDir, 'local', pagePath, vpName);
      const liveShot = screenshotFilename(outDir, 'live', pagePath, vpName);
      const diffShot = screenshotFilename(outDir, 'diff', pagePath, vpName);

      // Capture live
      try {
        await snapPage(page, liveUrl, liveShot, cfg.waitUntil, cfg.waitMsAfterLoad);
        await hideSelectors(page, cfg.hideSelectors);
        // re-screenshot if hideSelectors were applied (we already injected after goto)
        // But to ensure hiding applies we may re-screenshot:
        // (Note: For live, we may want to hide before capturing; we inject after load)
      } catch (err) {
        console.error(`Failed to capture live ${liveUrl}:`, err.message);
        failures++;
        continue;
      }

      // Capture local (we re-open because hideSelectors might persist; reload to apply)
      try {
        // reload a fresh page for local capture to avoid leftover modifications
        await page.goto('about:blank');
        await snapPage(page, localUrl, localShot, cfg.waitUntil, cfg.waitMsAfterLoad);
        // Hide selectors and re-screenshot to ensure masked
        if (cfg.hideSelectors && cfg.hideSelectors.length > 0) {
          await hideSelectors(page, cfg.hideSelectors);
          await page.screenshot({ path: localShot, fullPage: true });
        }
      } catch (err) {
        console.error(`Failed to capture local ${localUrl}:`, err.message);
        failures++;
        continue;
      }

      // Compare
      try {
        const { diffPixels, totalPixels } = compareImages(liveShot, localShot, diffShot);
        const percent = (diffPixels / totalPixels) * 100;

        const ok = percent <= (cfg.thresholdPercent || 0.1);
        results.push({
          page: pagePath,
          viewport: vpName,
          live: liveShot,
          local: localShot,
          diff: diffShot,
          diffPixels,
          totalPixels,
          percent,
          ok
        });

        const status = ok ? 'OK' : 'DIFF';
        console.log(`${status}: ${pagePath} [${vpName}] — ${percent.toFixed(4)}% different (${diffPixels}/${totalPixels})`);
        if (!ok) failures++;
      } catch (err) {
        console.error('Comparison failed for', pagePath, vpName, err);
        failures++;
      }
    }
  }

  await browser.close();

  // Print summary
  const failed = results.filter(r => !r.ok);
  console.log('--- Visual comparison summary ---');
  console.log(`Total comparisons: ${results.length}`);
  console.log(`Failures: ${failed.length}`);
  if (failed.length > 0) {
    console.log('Failed items (paths and viewports):');
    for (const f of failed) {
      console.log(` - ${f.page} [${f.viewport}]  diff: ${f.diff}  %: ${f.percent.toFixed(4)}`);
    }
    console.log(`Diffs and screenshots are in ${outDir}.`);
    process.exit(1);
  } else {
    console.log('All visual comparisons passed.');
    process.exit(0);
  }
})().catch(err => {
  console.error('Fatal error in visual comparison:', err);
  process.exit(2);
});

Notes and usage
- Start your local server before running. Example: if your app is started with npm start on localhost:3000, run it in one terminal, and in another run npm run visual:compare.
- The script writes screenshots and diffs into the output directory (visual-output by default).
- thresholdPercent is in percent; 0 means exact pixel match required. I recommend a small allowed percent (0.05–0.5) if you expect tiny anti-alias differences; set to 0 for strict.
- hideSelectors is important for dynamic content (ads, timestamps, animations). Add CSS selectors for elements to hide.
- If your pages require authentication or specific cookies, add code to set cookies or authenticate in Puppeteer before capturing.

CI integration (GitHub Actions example)
Add .github/workflows/visual-test.yml to run this after dependency changes (adapt trigger as needed):

name: Visual regression test
on:
  push:
    branches: [ dependabot/**, update-deps/**, main ]
  pull_request:
    paths:
      - '**/package-lock.json'
      - '**/package.json'

jobs:
  visual:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - name: Setup Node
        uses: actions/setup-node@v4
        with:
          node-version: 18
      - name: Install dependencies
        run: npm ci
      - name: Start local server
        # Adjust to your project's start command. Use a background process or a small server command.
        run: |
          npm run start &> server.log &
          # wait for server to be ready - replace with better healthcheck if available
          n=0; until curl -sSf http://localhost:3000/ > /dev/null || [ $n -ge 20 ]; do n=$((n+1)); sleep 1; done
      - name: Run visual comparison
        run: npm run visual:compare
      - name: Upload screenshots (on failure)
        if: failure()
        uses: actions/upload-artifact@v4
        with:
          name: visual-output
          path: visual-output

Tips & caveats
- Deterministic content: make pages deterministic for screenshots (e.g., use mock data in test mode). If not possible, use hideSelectors or add specific CSS to mask areas that change each load.
- FullPage screenshot: takes the full vertical length. If the live and local pages differ in content height (e.g., dynamic lists), diff will show differences. You can switch to fixed viewport-only screenshots if desired: change screenshot options to { path, fullPage: false } and ensure viewport height covers the part you care about.
- If your site relies on fonts that differ between environments, ensure the same fonts are installed in CI or use webfonts consistent across local and live.
- If you have responsive reflows that depend on content (e.g., different text length), test relevant viewports and include pages that are representative.

