const fs = require('fs');
const path = require('path');
const puppeteer = require('puppeteer');
const { PNG } = require('pngjs');
const pixelmatch = require('pixelmatch');

const CONFIG_PATH = path.resolve(process.cwd(), 'visual-config.json');

function readConfig() {
  if (!fs.existsSync(CONFIG_PATH)) {
    console.error('Config file not found:', CONFIG_PATH);
    process.exit(2);
  }
  return JSON.parse(fs.readFileSync(CONFIG_PATH, 'utf8'));
}

function ensureDir(dir) {
  fs.mkdirSync(dir, { recursive: true });
}

function safeName(pagePath) {
  if (pagePath === '/' || pagePath === '') return 'root';
  return pagePath.replace(/^\//, '').replace(/\//g, '_') || 'root';
}

function screenshotFilename(outputDir, which, pagePath, vpName) {
  const safePath = safeName(pagePath);
  return path.join(outputDir, `${safePath}__${vpName}__${which}.png`);
}

async function addHideCss(page, selectors = []) {
  if (!selectors || selectors.length === 0) return;
  const css = selectors.map(s => `${s} { visibility: hidden !important; opacity: 0 !important; pointer-events: none !important; }`).join('\n');
  await page.addStyleTag({ content: css });
}

async function snapPage(page, url, filePath, waitUntil = 'networkidle2', waitMsAfterLoad = 0, hideSelectors = []) {
  await page.goto(url, { waitUntil, timeout: 60000 });
  if (waitMsAfterLoad && waitMsAfterLoad > 0) {
    await page.waitForTimeout(waitMsAfterLoad);
  }
  // Inject hiding CSS (works after load)
  if (hideSelectors && hideSelectors.length > 0) {
    await addHideCss(page, hideSelectors);
    // wait a tiny bit so layout settles
    await page.waitForTimeout(50);
  }
  await page.screenshot({ path: filePath, fullPage: true });
}

function compareImages(imgPathA, imgPathB, outDiffPath, pixelmatchOptions = {}) {
  const bufA = fs.readFileSync(imgPathA);
  const bufB = fs.readFileSync(imgPathB);
  const imgA = PNG.sync.read(bufA);
  const imgB = PNG.sync.read(bufB);

  const width = Math.max(imgA.width, imgB.width);
  const height = Math.max(imgA.height, imgB.height);

  // create canvases and blit each image into top-left
  const canvasA = new PNG({ width, height, fill: true });
  const canvasB = new PNG({ width, height, fill: true });

  // default fill transparent
  PNG.bitblt(imgA, canvasA, 0, 0, imgA.width, imgA.height, 0, 0);
  PNG.bitblt(imgB, canvasB, 0, 0, imgB.width, imgB.height, 0, 0);

  const diff = new PNG({ width, height });
  const opts = Object.assign({ threshold: 0.1 }, pixelmatchOptions);
  const diffPixels = pixelmatch(canvasA.data, canvasB.data, diff.data, width, height, opts);

  fs.writeFileSync(outDiffPath, PNG.sync.write(diff));
  return { diffPixels, totalPixels: width * height };
}

